    {1434,"Forge of Aeons",0,2,{"wago"},0,{{id=3547,title="The Cave",description="The cave howls. The only way is forward.",criteriaTreeID=61233,orderIndex=0,rewardQuestID=0},{id=3549,title="Unwelcome Reminder",description="The draenei house shimmers into existence. A figment of the imagination?",criteriaTreeID=61548,orderIndex=1,rewardQuestID=0},{id=3550,title="Empathy",description="Echoes of the past, or a twist of emotion? There is no kindness here.",criteriaTreeID=61550,orderIndex=2,rewardQuestID=0},{id=3551,title="Sorrow",description="The swamp stinks of malevolence and anguish.",criteriaTreeID=61552,orderIndex=3,rewardQuestID=0},{id=3552,title="Comfort",description="Even in the most hopeless situations, there is respite.",criteriaTreeID=61561,orderIndex=4,rewardQuestID=0},{id=3553,title="The Serpent",description="Perhaps there is no relief?",criteriaTreeID=61563,orderIndex=5,rewardQuestID=0},{id=3554,title="Refuge",description="Perhaps retreating deeper is the only way to feel safe...",criteriaTreeID=61798,orderIndex=6,rewardQuestID=0},{id=3555,title="Delving",description="A distraction, that what must be what is needed.",criteriaTreeID=61800,orderIndex=7,rewardQuestID=0},{id=3561,title="Furious",description="It is unfair! Nothing is ever what it seems!",criteriaTreeID=61869,orderIndex=8,rewardQuestID=0},{id=3556,title="Shadows",description="Enemies in every shadow! How can the darkness be stopped?",criteriaTreeID=61802,orderIndex=9,rewardQuestID=0},{id=3570,title="In Hiding",description="Is the only way through this to remain hidden? Alone?",criteriaTreeID=62008,orderIndex=10,rewardQuestID=0},{id=3571,title="Out of Sight",description="This is a good place to hide. Safe. Secure. Away from everyone. Everything.",criteriaTreeID=62020,orderIndex=11,rewardQuestID=0},{id=3572,title="Possibilities",description="No. It won't stop. The only way is to soldier on. To defeat the fear, the frustration.",criteriaTreeID=62010,orderIndex=12,rewardQuestID=0},{id=3573,title="Dark Offer",description="Is there an easier way? Perhaps power is all that is needed... Strength. To become that fear.",criteriaTreeID=62012,orderIndex=13,rewardQuestID=0},{id=3579,title="Descent",description="Impossible! Purity. Abstinence. It is an offer that cannot be accepted.",criteriaTreeID=62067,orderIndex=14,rewardQuestID=0},{id=3574,title="Aspects",description="Kindness and courage are not the only truths. What of fear? What of frustration?",criteriaTreeID=62038,orderIndex=15,rewardQuestID=0},{id=3575,title="Demise",description="Is this where it all leads? To the very edge of obliteration?",criteriaTreeID=62045,orderIndex=16,rewardQuestID=0}}},
