    {2626,"Worldsoul Vision",0,0,{"wago"},0,{{id=8082,title="Primal Predators",description="These caverns were once home to fierce creatures, locked in a cycle of predation that ultimately led to their own extinction.",criteriaTreeID=0,orderIndex=0,rewardQuestID=0},{id=8083,title="Ton'kei the Fierce",description="Of all the predators to roam this land, Ton'kei spilled the most blood upon Azeroth's soil.",criteriaTreeID=0,orderIndex=1,rewardQuestID=0},{id=8084,title="Soothing the Worldsoul",description="Each terrifying predator defeated eases the memories of the pain of this place.",criteriaTreeID=0,orderIndex=2,rewardQuestID=0}}},
    {2627,"Worldsoul Vision",0,0,{"wago"},0,{{id=8085,title="Elemental Fury",description="Long before the machine speakers arrived, elemental creatures roamed untamed throughout this expanse, reshaping the landscape with their raw power.",criteriaTreeID=0,orderIndex=0,rewardQuestID=0},{id=8086,title="Rumblestone",description="Rumblestone knew only fury, and spent a lifetime carving cavernous scars into Azeroth's mountains and canyons.",criteriaTreeID=0,orderIndex=1,rewardQuestID=0},{id=8087,title="Soothing the Worldsoul",description="Each enraged elemental defeated eases the memories of the pain of this place.",criteriaTreeID=0,orderIndex=2,rewardQuestID=0}}},
    {2628,"Worldsoul Vision",0,0,{"wago"},0,{{id=8088,title="Descendants of Distant Waters",description="The kobyss and naga traded blows in battle for generations. Of all the ankoan tribes, only the kobyss matched the viciousness and violence of Azshara's armies.",criteriaTreeID=0,orderIndex=0,rewardQuestID=0},{id=8089,title="Zing'has the Brute",description="Shorelines were stained red with blood whenever Zing'has entered the fray.",criteriaTreeID=0,orderIndex=1,rewardQuestID=0},{id=8090,title="Soothing the Worldsoul",description="Each aquatic soldier defeated eases the memories of the pain of this place.",criteriaTreeID=0,orderIndex=2,rewardQuestID=0}}},
    {2629,"Worldsoul Vision",0,0,{"wago"},0,{{id=8091,title="Reign of the Old Gods",description="Long before the arrival of the Light, followers of the Old Gods darkened these caverns with their maddening misdeeds.",criteriaTreeID=0,orderIndex=0,rewardQuestID=0},{id=8092,title="Thystoria",description="Cruelty came naturally to the aqir, but Thystoria particularly reveled in causing pain.",criteriaTreeID=0,orderIndex=1,rewardQuestID=0},{id=8093,title="Soothing the Worldsoul",description="Each monster defeated eases the memories of the pain of this place.",criteriaTreeID=0,orderIndex=2,rewardQuestID=0}}},
    {2630,"Worldsoul Vision",0,0,{"wago"},0,{{id=8094,title="A Wounded Soul",description="When Sargeras plunged his sword into Azeroth, it tainted the very lifeblood of the world, unleashing monstrosities whose echoes still resonate to this day.",criteriaTreeID=0,orderIndex=0,rewardQuestID=0},{id=8095,title="Bloodscar",description="Bloodscar hungrily feasted upon the essence of anything unfortunate enough to cross its path.",criteriaTreeID=0,orderIndex=1,rewardQuestID=0},{id=8096,title="Soothing the Worldsoul",description="Each monstrosity defeated eases the memories of the pain of this place.",criteriaTreeID=0,orderIndex=2,rewardQuestID=0}}},
